import { type } from "arktype"

// ─── Sensitive field types with per-type redaction ───────────────────────────

/**
 * Password type: 12–128 chars, at least one lowercase, uppercase, digit, symbol.
 * Any validation error will show "<redacted>" instead of the raw value.
 */
const passwordType = type("string")
  .atLeastLength(12)
  .atMostLength(128)
  .matching(/[a-z]/)
  .matching(/[A-Z]/)
  .matching(/[0-9]/)
  .matching(/[^a-zA-Z0-9]/)
  .configure({
    actual: () => "<redacted>",
    problem: () => "must be a valid password (was <redacted>)",
  })

/**
 * SSN type: exactly matches NNN-NN-NNNN pattern.
 * Any validation error will show "<redacted>" instead of the raw value.
 */
const ssnType = type(/^\d{3}-\d{2}-\d{4}$/).configure({
  actual: () => "<redacted>",
  problem: () => "must be a valid SSN (was <redacted>)",
})

// ─── Main sign-up schema ─────────────────────────────────────────────────────

export const signUpSchema = type({
  username: "3 <= string <= 20 & /^[a-zA-Z0-9]+$/",
  password: passwordType,
  confirm: passwordType,
  ssn: ssnType,
}).narrow((data, ctx) => {
  if (data.confirm !== data.password) {
    ctx.error({
      expected: "equal to password",
      actual: "<redacted>",
      problem: "must equal password (was <redacted>)",
      path: ["confirm"],
    })
    return false
  }
  return true
})

export type SignUpData = typeof signUpSchema.infer

import { signUpSchema } from "./src/validator.ts"

async function main(): Promise<void> {
  // Read all stdin
  const chunks: Buffer[] = []
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer)
  }
  const raw = Buffer.concat(chunks).toString("utf8").trim()

  let payload: unknown
  try {
    payload = JSON.parse(raw)
  } catch {
    process.stdout.write(
      `INVALID: ${JSON.stringify({ byPath: { "": { message: "Input is not valid JSON" } } })}\n`
    )
    process.exit(0)
  }

  const result = signUpSchema(payload)

  if (result instanceof signUpSchema.$.type.errors) {
    // Validation failed — emit structured error JSON with byPath
    process.stdout.write(`INVALID: ${JSON.stringify(result)}\n`)
    process.exit(0)
  }

  // Validation succeeded
  process.stdout.write(`VALID\n${JSON.stringify(result)}\n`)
  process.exit(0)
}

