import { ArkErrors } from "arktype"
import { signUpSchema } from "./src/validator.ts"

const SENSITIVE_PATHS = new Set(["password", "confirm", "ssn"])

/**
 * Walk an ArkError's toJSON() representation and redact any `actual` /
 * `problem` values at sensitive paths (including nested intersection errors).
 */
function redactError(err: ReturnType<(typeof ArkErrors.prototype)[number]["toJSON"]>): typeof err {
  const propString: string = Array.isArray(err.path)
    ? (err.path as string[]).join(".")
    : String(err.path ?? "")

  const topKey = (err.path as string[])?.[0] ?? ""
  const isSensitive = SENSITIVE_PATHS.has(topKey)

  // Deep-redact nested intersection errors
  let errors = err.errors as typeof err[] | undefined
  if (errors) {
    errors = errors.map(redactError) as typeof errors
  }

  if (isSensitive) {
    return {
      ...err,
      actual: "<redacted>",
      problem: err.problem?.includes("<redacted>")
        ? err.problem
        : `must be valid (was <redacted>)`,
      message: err.message?.includes("<redacted>")
        ? err.message
        : `${propString} must be valid (was <redacted>)`,
      errors,
    }
  }

  return { ...err, errors }
}

async function main(): Promise<void> {
  // Read all stdin
  const chunks: Buffer[] = []
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer)
  }
  const raw = Buffer.concat(chunks).toString("utf8").trim()

  let payload: unknown
  try {
    payload = JSON.parse(raw)
  } catch {
    process.stdout.write(
      `INVALID: ${JSON.stringify({
        byPath: { "": { message: "Input is not valid JSON" } },
      })}\n`
    )
    process.exit(0)
  }

  const result = signUpSchema(payload)

  if (result instanceof ArkErrors) {
    // Build a redacted byPath map from the errors
    const byPath: Record<string, unknown> = {}
    for (const [path, err] of Object.entries(result.byPath)) {
      byPath[path] = redactError(err.toJSON() as ReturnType<(typeof ArkErrors.prototype)[number]["toJSON"]>)
    }

    process.stdout.write(`INVALID: ${JSON.stringify({ byPath })}\n`)
    process.exit(0)
  }

  // Validation succeeded
  process.stdout.write(`VALID\n${JSON.stringify(result)}\n`)
  process.exit(0)
