type PlainErrorObj = Record<string, unknown>

/**
 * Recursively sanitize a plain-object representation of an ArkError.
 * For sensitive fields:
 *   - `data` → "<redacted>"
 *   - `actual` → "<redacted>"
 *   - `problem` → "<redacted>" (if it doesn't already contain <redacted>)
 *   - `message` → "<redacted>" (if it doesn't already contain <redacted>)
 */
function sanitizeError(errObj: PlainErrorObj, sensitive: boolean): PlainErrorObj {
  const result: PlainErrorObj = {}
  for (const [k, v] of Object.entries(errObj)) {
    if (k === "errors" && Array.isArray(v)) {
      // Recurse into child errors – they are in the same sensitive context
      result[k] = v.map((child: unknown) =>
        typeof child === "object" && child !== null
          ? sanitizeError(child as PlainErrorObj, sensitive)
          : child
      )
    } else if (sensitive && k === "data") {
      result[k] = "<redacted>"
    } else if (sensitive && k === "actual") {
      result[k] = "<redacted>"
    } else if (sensitive && k === "problem") {
      const s = String(v ?? "")
      result[k] = s.includes("<redacted>") ? s : "<redacted>"
    } else if (sensitive && k === "message") {
      const s = String(v ?? "")
      result[k] = s.includes("<redacted>") ? s : "<redacted>"
    } else {
      result[k] = v
    }
  }
  return result
}

/**
 * Determine if a path array belongs to a sensitive field.
 */
function isSensitivePath(path: unknown): boolean {
  if (Array.isArray(path) && path.length > 0) {
    return SENSITIVE_PATHS.has(String(path[0]))
  }
  return false
}

